import { ref } from 'vue'
import { profile } from '@/api/profile'
import { showToast } from '@/components/ToastMessage'

export function useProfileData() {
  const loading = ref(false)
  const profileData = ref({
    basic_info: null,
    job_intention: null,
    work_experience: null,
    education: null,
    project: null,
    skill: null,
    certificate: null,
    language: null,
    portfolio: null,
    social_link: null
  })

  // 获取模块数据
  const fetchModuleData = async (moduleType) => {
    try {
      loading.value = true
      let response

      switch (moduleType) {
        case 'job_intention':
          response = await profile.jobIntention.get()
          break
        case 'work_experience':
          response = await profile.workExperience.list()
          break
        case 'education':
          response = await profile.education.list()
          break
        // ... 其他模块的数据获取
      }

      if (response?.data?.code === 200) {
        profileData.value[moduleType] = response.data.data
        return response.data.data
      }
      return null
    } catch (error) {
      console.error(`获取${moduleType}数据失败:`, error)
      return null
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    profileData,
    fetchModuleData
  }
}
